PREFIX fq: <https://www.purl.org/futuram/query#>
PREFIX futuram: <https://www.purl.org/futuram#>
SELECT ((?amt * ?im) AS ?kg)
       ((?ru * ?amt * ?im) AS ?uncert_kg)
WHERE {
  <https://www.purl.org/futuram#V0401010102_Y2025> fq:itemMass ?im .
  ?stmt a fq:Amount ;
        fq:whole <https://www.purl.org/futuram#V0401010102_Y2025> ;
        fq:constituent futuram:Copper ;
        fq:amount ?amt ;
        fq:relativeUncertainty ?ru .
}

