PREFIX rdfs:    <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?class ?label ?itemMass ?refYear WHERE {
  BIND(<https://www.purl.org/futuram#V0401010102_Y2025> AS ?class)
  ?class rdfs:label ?label .
  OPTIONAL { ?class fq:itemMass ?itemMass }
  OPTIONAL { ?class futuram:referenceYear ?refYear }
}

