PREFIX fq:      <https://www.purl.org/futuram/query#>
PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX rdfs:    <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?constituent ?label ?frac ?relUnc WHERE {
  <https://www.purl.org/futuram#V0401010102_Y2025> fq:contains ?amt .
  ?amt fq:constituent ?constituent ;
       fq:amount ?frac ;
       fq:relativeUncertainty ?relUnc .
  OPTIONAL { ?constituent rdfs:label ?label }
  FILTER(CONTAINS(LCASE(STR(?label)), "copper") || CONTAINS(LCASE(STR(?label)), "cu"))
}

