arguments.sparql_query:
PREFIX fq:    <https://www.purl.org/futuram/query#>
PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX rdfs:  <http://www.w3.org/2000/01/rdf-schema#>

SELECT (?amount AS ?share_kgkg)
       (?relUnc  AS ?relUnc)
       (?itemMass AS ?itemMass_kg)
       ((?amount * ?itemMass) AS ?kg)
       ((?relUnc * ?amount * ?itemMass) AS ?uncert_kg)
       ?constituent
WHERE {
  # Top-level Amount stmts on the WHOLE (HEV segment B 2025) where constituent is Copper
  ?stmt a fq:Amount ;
        fq:whole ?whole ;
        fq:constituent ?constituent ;
        fq:amount ?amount ;
        fq:relativeUncertainty ?relUnc .
  ?whole fq:itemMass ?itemMass .
  FILTER(?constituent IN (futuram:Copper))
  FILTER(?whole = futuram:V0401010102_Y2025)
}

